select mb.*, m.name, m.color_code, m.model, m.other_field5, m.other_field6, m.other_field7, m.other_field8, m.color, mc.name category, m.unit mUnit, ps.model supplier_model, ps.pack, s.supplier supplier_name from jsh_material_bom mb left join jsh_material_extend me on mb.bar_code=me.bar_code and ifnull(me.delete_Flag,'0') !='1' left join jsh_material m on m.id=me.material_id and ifnull(m.delete_Flag,'0') !='1' left join jsh_material_category mc on m.category_id = mc.id and ifnull(mc.delete_Flag,'0') !='1' left join jsh_product_supplier ps on mb.department = ps.id and ifnull(ps.delete_Flag,'0') !='1' left join jsh_supplier s on ps.supplier_id = s.id and ifnull(s.delete_Flag,'0') !='1' where 1=1 and (mb.upper is null or mb.upper = '')
